func solve(n int64, edges [][]int64) int64 {
	// Build adjacency list
	adj := make([][]Edge, n)
	for _, edge := range edges {
		adj[edge[0]] = append(adj[edge[0]], Edge{edge[0], edge[1], edge[2]})
	}

	// Dijkstra's algorithm with state tracking
	pq := make(PriorityQueue, 0)
	heap.Init(&pq)
	visited := make(map[int64]bool)
	visited[0] = true
	state := &State{node: 0, used: false, cost: 0}
	heap.Push(&pq, state)

	for pq.Len() > 0 {
		state := heap.Pop(&pq).(*State)
		if state.node == n-1 {
			return state.cost
		}

		for _, edge := range adj[state.node] {
			// Original direction
			newCost := state.cost + edge.weight
			if !visited[edge.to] {
				visited[edge.to] = true
				heap.Push(&pq, &State{node: edge.to, used: false, cost: newCost})
			}
		}

		// Check if we can flip the edge
		if !state.used {
			// Reverse the edge
			newCost := state.cost + 2*edge.weight
			if !visited[edge.to] {
				visited[edge.to] = true
				heap.Push(&pq, &State{node: edge.to, used: true, cost: newCost})
			}
		}
	}

	return -1
}
